)

func (f *CommandFactory) newBeadCommand() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "bead",
		Short: "Manage beads (portable work items)",
		Long: `Manage beads — portable, ephemeral work items with metadata.

Beads provide a lightweight work queue for AI agents and developers.
They track tasks, dependencies, and status without coupling to any
specific workflow methodology.

Examples:
  ddx bead init                                    # Initialize bead storage
  ddx bead create "Fix auth bug" --type bug        # Create a bead
  ddx bead list --status open                      # List open beads
  ddx bead ready                                   # Show beads ready for work
  ddx bead dep add <id> <dep-id>                   # Add a dependency
  ddx bead import --from jsonl beads.jsonl          # Import from JSONL`,
		Aliases: []string{"beads"},
		PersistentPreRunE: func(cmd *cobra.Command, args []string) error {
			serverreg.TryRegisterAsync(f.WorkingDir)
			return nil
		},
		Run: func(cmd *cobra.Command, args []string) {
			_ = cmd.Help()
		},
	}

	cmd.AddCommand(f.newBeadInitCommand())
	cmd.AddCommand(f.newBeadCreateCommand())
	cmd.AddCommand(f.newBeadShowCommand())
	cmd.AddCommand(f.newBeadUpdateCommand())
	cmd.AddCommand(f.newBeadCloseCommand())
	cmd.AddCommand(f.newBeadReopenCommand())
	cmd.AddCommand(f.newBeadListCommand())
	cmd.AddCommand(f.newBeadReadyCommand())
	cmd.AddCommand(f.newBeadBlockedCommand())
	cmd.AddCommand(f.newBeadStatusCommand())
	cmd.AddCommand(f.newBeadDepCommand())
	cmd.AddCommand(f.newBeadQueueCommand())
	cmd.AddCommand(f.newBeadEvidenceCommand())
	cmd.AddCommand(f.newBeadRoutingCommand())
	cmd.AddCommand(f.newBeadImportCommand())
	cmd.AddCommand(f.newBeadExportCommand())
	cmd.AddCommand(f.newBeadMergeCommand())
	cmd.AddCommand(f.newBeadReviewCommand())
	cmd.AddCommand(f.newBeadMetricsCommand())
	cmd.AddCommand(f.newBeadDoctorCommand())
	cmd.AddCommand(f.newBeadCooldownCommand())
	cmd.AddCommand(f.newBeadReconcileCommand())
	cmd.AddCommand(f.newBeadMigrateCommand())
	cmd.AddCommand(f.newBeadArchiveCommand())

	return cmd
}

// beadAutoCommit commits .ddx/beads.jsonl if git.auto_commit is "always".
// The operation string describes what happened (e.g. "create ddx-abc123").
// Errors are silently ignored — auto-commit is best-effort.
// When a commit lands, the resulting SHA is returned.
func (f *CommandFactory) beadAutoCommit(operation string) string {
	workspaceRoot := f.beadWorkspaceRoot()
	if workspaceRoot == "" {
		workspaceRoot = f.WorkingDir
	}

	cfg, err := config.LoadWithWorkingDir(workspaceRoot)
	if err != nil {
		return ""
	}
	if cfg.Git == nil {
		return ""
	}
	acCfg := gitpkg.AutoCommitConfig{
		AutoCommit:   cfg.Git.AutoCommit,
		CommitPrefix: cfg.Git.CommitPrefix,
	}
	beadsFile := filepath.Join(workspaceRoot, ".ddx", "beads.jsonl")
	sha, _ := gitpkg.AutoCommit(beadsFile, "beads", operation, acCfg)
	return sha
}

func (f *CommandFactory) resolveCommitSHA(commitSHA string) (string, error) {
	if commitSHA == "" {
		return "", nil
	}

	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()

	repoDir := f.WorkingDir
	if repoDir == "" {
		repoDir = "."
	}

	if isFullCommitSHA(commitSHA) && !gitpkg.IsRepository(repoDir) {
		return commitSHA, nil
	}

	cmd := gitpkg.Command(ctx, repoDir, "rev-parse", "--verify", commitSHA+"^{commit}")
	out, err := cmd.Output()
	if err != nil {
		return "", fmt.Errorf("git rev-parse %s: %w", commitSHA, err)
	}
	return strings.TrimSpace(string(out)), nil
}

func isFullCommitSHA(commitSHA string) bool {
	if len(commitSHA) != 40 {
		return false
	}
	for i := 0; i < len(commitSHA); i++ {
		c := commitSHA[i]
		if c >= '0' && c <= '9' {
			continue
		}
		if c >= 'a' && c <= 'f' {
			continue
		}
		if c >= 'A' && c <= 'F' {
			continue
		}
		return false
	}
	return true
}

func (f *CommandFactory) resolveClosingCommitSHA(commitSHA string) (string, error) {
	normalizedCommitSHA, err := f.resolveCommitSHA(commitSHA)
	if err != nil {
		return "", fmt.Errorf("invalid closing_commit_sha %q: %w", commitSHA, err)
	}
	if normalizedCommitSHA == "" {
		return "", fmt.Errorf("invalid closing_commit_sha %q: empty value", commitSHA)
	}
	return normalizedCommitSHA, nil
}

// commitIsMetadataOnlyTrackerBackfill reports whether the given commit changed
// only bead tracker state. Closing provenance is suppressed only for pure
// tracker backfills that touch .ddx/beads.jsonl and nothing else.
func (f *CommandFactory) commitIsMetadataOnlyTrackerBackfill(commitSHA string) bool {
	if commitSHA == "" {
		return false
	}

	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()

	cmd := gitpkg.Command(ctx, f.WorkingDir, "show", "--pretty=format:", "--name-only", commitSHA)
	out, err := cmd.Output()
	if err != nil {
		return false
	}

	for _, line := range strings.Split(string(out), "\n") {
		path := strings.TrimSpace(line)
		if path == "" {
			continue
		}
		if path != ".ddx/beads.jsonl" {
			return false
		}
	}

	return true
}

func isReviewCloseBead(b *bead.Bead) bool {
	if b == nil {
		return false
	}
	for _, label := range b.Labels {
		switch label {
		case "action:review", "kind:review", "phase:review", "review-finding":
			return true
		}
	}
	return false
}

func (f *CommandFactory) beadWorkspaceRoot() string {
	dir := os.Getenv("DDX_BEAD_DIR")
	if dir != "" {
		if filepath.Base(dir) == ".ddx" {
			if !filepath.IsAbs(dir) && f.WorkingDir != "" {
				if workspaceRoot := gitpkg.FindNearestDDxWorkspace(f.WorkingDir); workspaceRoot != "" {
					return workspaceRoot
				}
				dir = filepath.Join(f.WorkingDir, dir)
			}
			return filepath.Dir(dir)
		}
		if !filepath.IsAbs(dir) && f.WorkingDir != "" {
			return filepath.Join(f.WorkingDir, dir)
		}
		return dir
	}
	if f.WorkingDir == "" {
		return ""
	}
	if workspaceRoot := gitpkg.FindNearestDDxWorkspace(f.WorkingDir); workspaceRoot != "" {
		return workspaceRoot

package bead

import (
	"fmt"
	"time"
)

const queueRankKey = "queue-rank"
const queueRankStep = 10

type queueOp int

const (
	queueOpTop queueOp = iota
	queueOpMoveBefore
	queueOpMoveAfter
)

// QueueTop moves a bead to the front of its priority bucket.
func (s *Store) QueueTop(id string) error {
	return s.queueReorder(id, "", queueOpTop)
}

// QueueMove reorders a bead relative to another bead in the same priority bucket.
func (s *Store) QueueMove(id, otherID string, before bool) error {
	if before {
		return s.queueReorder(id, otherID, queueOpMoveBefore)
	}
	return s.queueReorder(id, otherID, queueOpMoveAfter)
}

// QueueClear removes the explicit queue-rank from a bead.
func (s *Store) QueueClear(id string) error {
	return s.WithLock(func() error {
		beads, _, err := s.readAllLatestRaw()
		if err != nil {
			return err
		}

		now := time.Now().UTC()
		found := false
		for i := range beads {
			if beads[i].ID != id {
				continue
			}
			found = true
			if beads[i].Extra != nil {
				delete(beads[i].Extra, queueRankKey)
				if len(beads[i].Extra) == 0 {
					beads[i].Extra = nil
				}
			}
			beads[i].UpdatedAt = now
			break
		}
		if !found {
			return fmt.Errorf("bead: not found: %s", id)
		}
		return s.WriteAll(beads)
	})
}

func (s *Store) queueReorder(id, otherID string, op queueOp) error {
	return s.WithLock(func() error {
		beads, _, err := s.readAllLatestRaw()
		if err != nil {
			return err
		}

		indexByID := make(map[string]int, len(beads))
		for i := range beads {
			indexByID[beads[i].ID] = i
		}

		targetIdx, ok := indexByID[id]
		if !ok {
			return fmt.Errorf("bead: not found: %s", id)
		}

		targetPriority := beads[targetIdx].Priority
		if op != queueOpTop {
			otherIdx, ok := indexByID[otherID]
			if !ok {
				return fmt.Errorf("bead: not found: %s", otherID)
			}
			if beads[otherIdx].Priority != targetPriority {
				return fmt.Errorf("bead: queue move limited to one priority bucket: %s (P%d) and %s (P%d)", id, targetPriority, otherID, beads[otherIdx].Priority)
			}
		}

		bucket := make([]Bead, 0, len(beads))
		for _, bead := range beads {
			if bead.Priority == targetPriority {
				bucket = append(bucket, bead)
			}
		}
		if len(bucket) == 0 {
			return fmt.Errorf("bead: not found: %s", id)
		}

		sortBeadsForQueue(bucket)
		desired := reorderQueueBucket(bucket, id, otherID, op)

		if rank, ok := queueTargetRank(desired, id); ok {
			now := time.Now().UTC()
			idx := indexByID[id]
			if beads[idx].Extra == nil {
				beads[idx].Extra = make(map[string]any)
			}
			beads[idx].Extra[queueRankKey] = rank
			beads[idx].UpdatedAt = now
			return s.WriteAll(beads)
		}

		now := time.Now().UTC()
		for i, bead := range desired {
			idx := indexByID[bead.ID]
			if beads[idx].Extra == nil {
				beads[idx].Extra = make(map[string]any)
			}
			beads[idx].Extra[queueRankKey] = i * queueRankStep
			beads[idx].UpdatedAt = now
		}

		return s.WriteAll(beads)
	})
}

func queueTargetRank(desired []Bead, targetID string) (int, bool) {
	targetIdx := -1
	for i, bead := range desired {
		if bead.ID == targetID {
			targetIdx = i
			break
		}
	}
	if targetIdx < 0 {
		return 0, false
	}

	for i := 0; i < targetIdx; i++ {
		if _, ok := parseQueueRank(desired[i].Extra[queueRankKey]); !ok {
			return 0, false
		}
	}

	var prevRank *int
	for i := targetIdx - 1; i >= 0; i-- {
		if rank, ok := parseQueueRank(desired[i].Extra[queueRankKey]); ok {
			prevRank = &rank
			break
		}
	}

	var nextRank *int
	for i := targetIdx + 1; i < len(desired); i++ {
		if rank, ok := parseQueueRank(desired[i].Extra[queueRankKey]); ok {
			nextRank = &rank
			break
		}
	}

	switch {
	case prevRank != nil && nextRank != nil:
		if *nextRank-*prevRank <= 1 {
			return 0, false
		}
		return (*prevRank + *nextRank) / 2, true
	case prevRank != nil:
		return *prevRank + 1, true
	case nextRank != nil:
		return *nextRank - 1, true
	default:
		return 0, true
	}
}

func reorderQueueBucket(bucket []Bead, targetID, otherID string, op queueOp) []Bead {
	if len(bucket) <= 1 {
		return bucket
	}

	targetIdx := -1
	otherIdx := -1
	for i, bead := range bucket {
		switch bead.ID {
		case targetID:
			targetIdx = i
		case otherID:
			otherIdx = i
		}
	}
	if targetIdx < 0 {
		return bucket
	}

	out := append([]Bead(nil), bucket...)
	target := out[targetIdx]
	out = append(out[:targetIdx], out[targetIdx+1:]...)

	switch op {
	case queueOpTop:
		return append([]Bead{target}, out...)
	case queueOpMoveBefore, queueOpMoveAfter:
		if otherIdx < 0 || targetID == otherID {
			return bucket
		}
		if targetIdx < otherIdx {
			otherIdx--
		}
		insertAt := otherIdx
		if op == queueOpMoveAfter {
			insertAt++
		}
		if insertAt < 0 {
			insertAt = 0
		}
		if insertAt > len(out) {
			insertAt = len(out)
		}
		out = append(out, Bead{})
		copy(out[insertAt+1:], out[insertAt:])
		out[insertAt] = target
		return out
	default:
		return bucket
	}
}

package bead

import (
	"fmt"
	"strings"
	"time"
)

// Bead represents a portable work item with metadata.
// The schema matches bd/br JSONL format for interchange compatibility.
// Unknown fields from external sources are preserved in Extra.
type Bead struct {
	ID        string    `json:"id"`
	Title     string    `json:"title"`
	Status    string    `json:"status"`
	Priority  int       `json:"priority"`
	IssueType string    `json:"issue_type"`
	Owner     string    `json:"owner,omitempty"`
	CreatedAt time.Time `json:"created_at"`
	CreatedBy string    `json:"created_by,omitempty"`
	UpdatedAt time.Time `json:"updated_at"`

	// Optional fields (bd-compatible)
	Labels      []string `json:"labels,omitempty"`
	Parent      string   `json:"parent,omitempty"`
	Description string   `json:"description,omitempty"`
	Acceptance  string   `json:"acceptance,omitempty"`
	Notes       string   `json:"notes,omitempty"`

	// Dependencies use bd-compatible format
	Dependencies []Dependency `json:"dependencies,omitempty"`

	// Extra holds unknown fields for round-trip preservation.
	// Workflow-specific fields (e.g. HELIX spec-id, execution-eligible)
	// are stored here and written back on save.
	Extra map[string]any `json:"-"`
}

// Dependency represents a link between two beads (bd-compatible format).
type Dependency struct {
	IssueID     string `json:"issue_id"`
	DependsOnID string `json:"depends_on_id"`
	Type        string `json:"type"` // "blocks", "related", etc.
	CreatedAt   string `json:"created_at,omitempty"`
	CreatedBy   string `json:"created_by,omitempty"`
	Metadata    string `json:"metadata,omitempty"`
}

// BeadEvent records append-only execution evidence.
type BeadEvent struct {
	Kind      string    `json:"kind"`
	Summary   string    `json:"summary,omitempty"`
	Body      string    `json:"body,omitempty"`
	Actor     string    `json:"actor,omitempty"`
	CreatedAt time.Time `json:"created_at"`
	Source    string    `json:"source,omitempty"`
}

// Status constants
const (
	StatusOpen       = "open"
	StatusInProgress = "in_progress"
	StatusClosed     = "closed"
	// StatusBlocked marks a bead that is not eligible for agent dispatch —
	// either decomposed into child beads by the triage gate or parked for
	// human intervention after a triage-overflow event. Blocked beads are
	// excluded from ReadyExecution and will not be auto-dispatched.
	StatusBlocked = "blocked"
	// StatusProposed marks an operator-prompt bead awaiting approval. It is
	// excluded from execute-loop drain until transitioned to open via the
	// approval flow, or to cancelled when the operator declines it.
	StatusProposed = "proposed"
	// StatusCancelled marks a bead that was rejected before any execution
	// took place (e.g. an operator-prompt bead the user chose not to run).
	StatusCancelled = "cancelled"
)

// CanonicalStatuses is the single source of truth for the persisted bead
// status enumeration. It mirrors the bd/br canonical set documented in
// TD-031 §2 and the JSON Schema enum at
// cli/internal/bead/schema/bead-record.schema.json. The CI guard tests in
// sync_test.go assert that schema, TD doc, and Go source agree with this
// list; adding or removing a value here without updating the schema and TD
// will fail CI.
var CanonicalStatuses = []string{
	StatusOpen,
	StatusInProgress,
	StatusClosed,
	StatusBlocked,
	StatusProposed,
	StatusCancelled,
}

// IsCanonicalStatus reports whether s is one of the persisted bead statuses
// in CanonicalStatuses.
func IsCanonicalStatus(s string) bool {
	for _, c := range CanonicalStatuses {
		if c == s {
			return true
		}
	}
	return false
}

// IssueType constants
const (
	// IssueTypeOperatorPrompt is the bead type used for operator-submitted
	// prompts that the execute-loop runs as instructions.
	IssueTypeOperatorPrompt = "operator-prompt"
)

// Default labels and other defaults for operator-prompt beads.
const (
	OperatorPromptLabelKind   = "kind:operator-prompt"
	OperatorPromptLabelSource = "source:web-ui"
	// OperatorPromptDefaultAcceptance is the auto-AC stub used when an
	// operator submits a prompt without explicit acceptance criteria. The
	// structural AC verifier is skipped for operator-prompt beads, so this
	// stub stands as a human-readable contract only.
	OperatorPromptDefaultAcceptance = "Agent must produce a diff or no_changes rationale; the prompt body is the contract."
)

// OperatorPromptMutationGuard enforces the no-self-mutation rule from
// Story 15: an operator-prompt bead's execution may not create, edit, or
// close another operator-prompt bead. The guard returns nil when the
// mutation is allowed and a non-nil error when it must be rejected.
//
// actorIssueType is the issue_type of the bead currently being executed
// (empty when no operator-prompt context is active). targetIssueType is
// the issue_type of the bead about to be mutated.
//
// Allow/deny matrix:
//
//	actor=""               , target=*                → allow
//	actor="task"           , target=*                → allow
//	actor="operator-prompt", target!="operator-prompt" → allow
//	actor="operator-prompt", target=="operator-prompt" → deny
func OperatorPromptMutationGuard(actorIssueType, targetIssueType string) error {
	if actorIssueType != IssueTypeOperatorPrompt {
		return nil
	}
	if targetIssueType != IssueTypeOperatorPrompt {
		return nil
	}
	return fmt.Errorf("bead: operator-prompt bead may not mutate another operator-prompt bead")
}

// NewOperatorPromptBead constructs a fresh operator-prompt bead from a raw
// prompt string, applying the Story 15 template defaults: title is the first
// non-empty line of the prompt, full prompt body is preserved verbatim in the
// description, default labels are kind:operator-prompt + source:web-ui, the
// status starts in `proposed` (approval flow), priority defaults to the
// caller-supplied tier (clamped to MinPriority..MaxPriority), and the
// acceptance field carries the auto-AC stub.
//
// The returned bead is not persisted; callers feed it to Store.Create which
// will assign the ID and CreatedAt/UpdatedAt timestamps.
func NewOperatorPromptBead(prompt string, defaultTier int) *Bead {
	body := strings.TrimSpace(prompt)
	title := body
	if i := strings.IndexByte(body, '\n'); i >= 0 {
		title = strings.TrimSpace(body[:i])
	}
	if title == "" {
		title = "(empty operator prompt)"
	}
	tier := defaultTier
	if tier < MinPriority {
		tier = MinPriority
	}
	if tier > MaxPriority {
		tier = MaxPriority
	}
	return &Bead{
		Title:       title,
		IssueType:   IssueTypeOperatorPrompt,
		Status:      StatusProposed,
		Priority:    tier,
		Labels:      []string{OperatorPromptLabelKind, OperatorPromptLabelSource},
		Description: body,
		Acceptance:  OperatorPromptDefaultAcceptance,
	}
}

// Default values
const (
	DefaultType     = "task"
	DefaultStatus   = StatusOpen
	DefaultPriority = 2
	DefaultPrefix   = "bx" // used only when repo name detection fails
	MinPriority     = 0
	MaxPriority     = 4
)

// StatusCounts holds aggregate counts for a bead store.
type StatusCounts struct {
	Open    int `json:"open"`
	Closed  int `json:"closed"`
	Blocked int `json:"blocked"`
	Ready   int `json:"ready"`
	Total   int `json:"total"`
}

// Blocker kinds surfaced through BlockedAll. These strings are part of the
// external DDx contract (HELIX reads them to decide how to handle a blocker).
const (
	BlockerKindDependency         = "dependency"
	BlockerKindBlockedStatus      = "blocked-status"
	BlockerKindRetryCooldown      = "retry-cooldown"
	BlockerKindNeedsInvestigation = "needs-investigation"
	BlockerKindNotEligible        = "not-execution-eligible"
	BlockerKindSuperseded         = "superseded"
	BlockerKindEpicOnly           = "epic-only"
)

// Blocker describes why an open bead is currently not runnable. Either
// unclosed dependencies exist, or an execute-loop cooldown has parked the
// bead until NextEligibleAt.
type Blocker struct {
	Kind           string   `json:"kind"`
	NextEligibleAt string   `json:"next_eligible_at,omitempty"`
	UnclosedDepIDs []string `json:"unclosed_dep_ids,omitempty"`
	LastStatus     string   `json:"last_status,omitempty"`
	LastDetail     string   `json:"last_detail,omitempty"`
	Reason         string   `json:"reason,omitempty"`
}

// BlockedBead pairs a bead with its blocker classification.
type BlockedBead struct {
	Bead
	Blocker Blocker `json:"blocker"`
}

// DepIDs returns a flat list of dependency IDs for this bead.
func (b *Bead) DepIDs() []string {
	var ids []string
	for _, d := range b.Dependencies {
		ids = append(ids, d.DependsOnID)
	}
	return ids
}

// HasDep returns true if the bead depends on the given ID.
func (b *Bead) HasDep(id string) bool {
	for _, d := range b.Dependencies {
		if d.DependsOnID == id {
			return true
		}
	}
	return false
}

