	case float32:
		return int(v), v == float32(int(v))

		return int(v), v == float32(int(v))
	case float64:
		return int(v), v == float64(int(v))
	case json.Number:
		if n, err := v.Int64(); err == nil {
			return int(n), true
		}
		if f, err := v.Float64(); err == nil {
			return int(f), f == float64(int(f))
		}
	case string:
		if n, err := strconv.Atoi(strings.TrimSpace(v)); err == nil {
			return n, true
		}
	}
	return 0, false
}

// Status returns aggregate counts.
func (s *Store) Status() (*StatusCounts, error) {
	beads, err := s.ReadAll()
	if err != nil {
		return nil, err
	}
	ready, err := s.Ready()
	if err != nil {
		return nil, err
	}
	blocked, err := s.Blocked()
	if err != nil {
		return nil, err
	}

	// Pull in archive partner so totals survive `bead migrate` — the archive
	// only carries closed beads, so Ready/Blocked aren't affected.
	seen := make(map[string]bool, len(beads))
	all := make([]Bead, 0, len(beads))
	for _, b := range beads {
		if seen[b.ID] {
			continue
		}
		seen[b.ID] = true
		all = append(all, b)
	}
	if s.Collection == DefaultCollection {
		archive := s.archivePartner()
		if archived, aerr := archive.ReadAll(); aerr == nil {
			for _, b := range archived {
				if seen[b.ID] {
					continue
				}
				seen[b.ID] = true
				all = append(all, b)
			}
		}
	}

	counts := &StatusCounts{Total: len(all), Ready: len(ready), Blocked: len(blocked)}
	for _, b := range all {
		switch b.Status {
		case StatusOpen:
			counts.Open++
		case StatusClosed:
			counts.Closed++
		}
	}
	return counts, nil
}

